对=的重载(实现深拷贝)例1class point;
class Array
&#123;
private:
    point *p;
    int size;
public:
    Array(Array &amp;a)
    &#123;
        size &#x3D; a.size;
        p &#x3D; new point[size];
        for(int i &#x3D; 0;i &lt; size;i++)
            p[i] &#x3D; a.p[i];
    &#125;&#x2F;&#x2F;拷贝复制函数，少了这个会出问题
    Array(int n, point pp)
    &#123;
        size &#x3D; n;
        p &#x3D; new point[size];
        for(int i &#x3D; 0;i &lt; size;i++)
            p[i] &#x3D; pp;&#x2F;&#x2F;经过实践，发现这一步是将point类的数据导入到Array类
       &#x2F;&#x2F;之前做的时候没有把pp赋给p[i]，最后结果输出要么是0要么是不规则数
    &#125;
    ~Array()&#123;&#125;
    Array &amp;operator&#x3D;(Array&amp;a)
    &#123;
        if(&amp;a !&#x3D; this)
        &#123;
            if(size !&#x3D; a.size)
            &#123;
                delete[] p;
                size &#x3D; a.size;
                p &#x3D; new point[size];
            &#125;
            for(int i &#x3D; 0;i &lt; size;i++)
                p[i] &#x3D; a.p[i];
            &#x2F;&#x2F;开辟新空间，深拷贝，把a的p数组传给this
        &#125;
        return *this;
    &#125;
&#125;;


