对+=的重载class mystr
&#123;
private:
    char *str;
    int size;
public:
    mystr &amp;operator+&#x3D;(mystr &amp;ss)
    &#123;
        size +&#x3D; ss.size;
        strcat(str,ss.str);
        return *this;
        &#x2F;*错误示范
        mystr s1;
        s1.size &#x3D; size + ss.size;
        s1.str &#x3D; new char[size+1];
        s1.str &#x3D; strcat(str,ss.str);
        return s1;
        *&#x2F;
        &#x2F;&#x2F;这种方式在win32下会显示乱码，在Linux下会提示被释放两次，并且不输出字符，无需再申请一个临时变量储存数据
    &#125;
