代码如下
#include &lt;bits&#x2F;stdc++.h&gt;
using namespace std;
double book[100], dis[100], MAX &#x3D; 99999, maps[100][100];
vector&lt;double&gt; length(0);
&#x2F;&#x2F; vector&lt;double&gt; ttt(0);
class point
&#123;
private:
    double x, y;

public:
    double getx() const &#123; return x; &#125;
    double gety() const &#123; return y; &#125;
    void set()
    &#123;
        cin &gt;&gt; x &gt;&gt; y;
    &#125;
&#125;;
double calc(point p1, point p2)
&#123;
    double l1, l2;
    l1 &#x3D; (p1.getx() - p2.getx()) * (p1.getx() - p2.getx());
    l2 &#x3D; (p1.gety() - p2.gety()) * (p1.gety() - p2.gety());
    return sqrt(l1 + l2);
&#125;

int main()
&#123;
    int n &#x3D; 5, m &#x3D; 10, i, j;
    int min, minIndex;
    double sum &#x3D; 0;
    vector&lt;point&gt; pp(6);
    for (int i &#x3D; 1; i &lt;&#x3D; 5; i++)
    &#123;
        pp[i].set();
    &#125;
    &#x2F;&#x2F; 对maps初始化，除了自己到自己距离是0，其他都是边界值
    for (i &#x3D; 1; i &lt;&#x3D; n;i++)
    &#123;
        for (j &#x3D; 1; j &lt;&#x3D; n;j++)
        &#123;
            if(i !&#x3D; j)
                maps[i][j] &#x3D; MAX;
            else
                maps[i][j] &#x3D; 0;
        &#125;
    &#125;
    &#x2F;&#x2F; 输入数据，输入无向图
    for (int i &#x3D; 1; i &lt; 6;i++)
    &#123;
        for (int j &#x3D; i + 1; j &lt; 6;j++)
        &#123;
            double temp &#x3D; calc(pp[i], pp[j]);
            length.push_back(temp);
            maps[i][j] &#x3D; temp;
            maps[j][i] &#x3D; temp;
        &#125;
    &#125;
    &#x2F;&#x2F; 初始化距离数组，默认把离1最近的找出来储存起来
    for (i &#x3D; 1; i &lt;&#x3D; n; i++)
        dis[i] &#x3D; maps[1][i];
    book[1] &#x3D; 1;
    for (i &#x3D; 1; i &lt;&#x3D; n - 1; i++)
    &#123;
        min &#x3D; MAX;
    &#x2F;&#x2F; 对最小值复制，寻找离树最近的点
        for (j &#x3D; 1; j &lt;&#x3D; n; j++)
        &#123;
            if (book[j] &#x3D;&#x3D; 0 &amp;&amp; dis[j] &lt; min)
            &#123;
                min &#x3D; dis[j];
                minIndex &#x3D; j;
            &#125;
        &#125;
        &#x2F;&#x2F; 标记这个点被访问过
        book[minIndex] &#x3D; 1;
        sum +&#x3D; dis[minIndex];
        for (j &#x3D; 1; j &lt;&#x3D; n; j++)
        &#123;
        &#x2F;&#x2F; 如果这个点没被访问过，如果距离更近就更新
            if (book[j] &#x3D;&#x3D; 0 &amp;&amp; maps[minIndex][j] &lt; dis[j])
                dis[j] &#x3D; maps[minIndex][j];
        &#125;
    &#125;
    cout.setf(ios::fixed);
    cout &lt;&lt; setprecision(6) &lt;&lt; sum &lt;&lt; endl;
    cout &lt;&lt; endl;
    &#x2F;&#x2F; 输出最小生成树
&#125;

