&#x2F;*链表合集*&#x2F;
#include&lt;iostream&gt;
#include&lt;cstdlib&gt;
using namespace std;
typedef struct node&#123;
    int a;
    struct node *next;
&#125; Node;
&#x2F;&#x2F;排序
void Sort(Node*head)&#123;
    node *p, *s, *pt;
    p &#x3D; head;
    s &#x3D; p-&gt;next;
    while (p-&gt;next !&#x3D; NULL)&#123;
        while(s-&gt;next !&#x3D; NULL)&#123;
            if(p-&gt;next &gt; s-&gt;next)&#123;
                pt-&gt;next &#x3D; p-&gt;next;
                p-&gt;next &#x3D; s-&gt;next;
                s-&gt;next &#x3D; pt-&gt;next;
            &#125;
            s &#x3D; s-&gt;next;
        &#125;
        p &#x3D; p-&gt;next;
        pt &#x3D; s;
    &#125;
&#125;

Node *add(Node*head,int num)&#123;&#x2F;&#x2F;在表尾插入元素
    Node *p &#x3D; NULL, *pr &#x3D; head;
    p &#x3D; (Node *)malloc(sizeof(Node));
    if(p &#x3D;&#x3D; NULL)&#123;
        cout &lt;&lt; &quot;no enough memory to allocate&quot;;
    &#125;
    if(head &#x3D;&#x3D; NULL)&#123;
        head &#x3D; p;
    &#125;else&#123;
        while(pr-&gt;next !&#x3D; NULL)&#123;
            pr &#x3D; pr-&gt;next;
        &#125;
        pr-&gt;next &#x3D; p;
    &#125;
    p-&gt;a &#x3D; num;
    p-&gt;next &#x3D; NULL;
    return head;
&#125;
&#x2F;&#x2F;打印链表
void show(Node*head)&#123;
    Node *p &#x3D; head;
    while(p !&#x3D; NULL)&#123;
        cout &lt;&lt; p-&gt;a &lt;&lt; &quot; &quot;;
        p &#x3D; p-&gt;next;
    &#125;
&#125;

void del(Node*head)&#123;&#x2F;&#x2F;释放申请的内存空间
    Node *p &#x3D; head, *pr &#x3D; NULL;
    while(p !&#x3D; NULL)&#123;
        pr &#x3D; p;
        p &#x3D; p-&gt;next;
        free(pr);
    &#125;
&#125;
&#x2F;&#x2F;删除链表里某一个节点
Node* Delete(Node*head,int num)&#123;
    Node *p &#x3D; head, *pr &#x3D; head;
    &#x2F;&#x2F;pr是目标元素前一个节点
    if(head &#x3D;&#x3D; NULL)&#123;
        cout &lt;&lt; &quot;empty table&quot;;
        return head;&#x2F;&#x2F;空表退出
    &#125;
    while(num !&#x3D; p-&gt;a &amp;&amp; p-&gt;next !&#x3D; NULL)&#123;
        &#x2F;&#x2F;未找到且不是空表
        pr &#x3D; p;
        p &#x3D; p-&gt;next;&#x2F;&#x2F;p直接指向当前节点的下一节点
    &#125;
    if(num &#x3D;&#x3D; p-&gt;a)&#123;&#x2F;&#x2F;找到了待删除节点
        if(p &#x3D;&#x3D; head)&#123;
            head &#x3D; p-&gt;next;&#x2F;&#x2F;直接让头指针指向待删除结点p的下一节点
        &#125;else&#123;
            pr-&gt;next &#x3D; p-&gt;next;
            &#x2F;&#x2F;前一节点的指针域指向待删除结点的下一节点
        &#125;
        free(p);
    &#125;else&#123;&#x2F;&#x2F;到表尾且没找到
        cout &lt;&lt; &quot;not found&quot;;
    &#125;
    return head;
&#125;
&#x2F;&#x2F;在链表里插入元素
Node* insert(Node*head,int num)&#123;
    Node *pr &#x3D; head, *p &#x3D; head, *temp &#x3D; NULL;
    p &#x3D; (Node *)malloc(sizeof(Node));
    if(p &#x3D;&#x3D; NULL)&#123;
        cout &lt;&lt; &quot;no enough memory&quot;;
        exit(0);
    &#125;
    p-&gt;next &#x3D; NULL;&#x2F;&#x2F;待插入节点指针域为空指针
    p-&gt;a &#x3D; num;&#x2F;&#x2F;待插入节点的数值域为num
    if(head &#x3D;&#x3D; NULL)&#123;
        head &#x3D; p;&#x2F;&#x2F;若原链表为空表，待插入节点为头节点
    &#125;else&#123;&#x2F;&#x2F;若为非空
    &#x2F;&#x2F;若未找到待插入节点的位置且未找到表尾则继续找
        while(pr-&gt;a &lt; num &amp;&amp; pr-&gt;next !&#x3D; NULL)&#123;
            temp &#x3D; pr;&#x2F;&#x2F;temp保存当前节点的下一节点
            pr &#x3D; pr-&gt;next;&#x2F;&#x2F;pr指向当前节点的下一节点
        &#125;
        if(pr-&gt;a &gt;&#x3D; num)&#123;
            if(pr &#x3D;&#x3D; head)&#123;&#x2F;&#x2F;若在头节点前插入新节点
                p-&gt;next &#x3D; head;
            &#x2F;&#x2F;将新节点的指针域指向原链表的头节点
                head &#x3D; p;&#x2F;&#x2F;让head指向新节点
            &#125;else&#123;&#x2F;&#x2F;在链表中部插入新节点
            &#x2F;&#x2F;进行排序
                pr &#x3D; temp;
                p-&gt;next &#x3D; pr-&gt;next;
                pr-&gt;next &#x3D; p;
            &#125;
        &#125;else&#123;&#x2F;&#x2F;若在表尾插入新节点
            pr-&gt;next &#x3D; p;&#x2F;&#x2F;让末节点的指针域指向新节点
        &#125;
    &#125;
    return head;&#x2F;&#x2F;返回插入新节点猴的链表头指针head的值
&#125;

